void navigateToAppropriateRoute(String initialLink) async {
  String path = Uri.parse(initialLink).path;

  if (path.startsWith("/profile")) {
    final id = path.split('/')[2];
    Navigator.pushNamed(NavigationKey.currentState.currentContext, '/ProfilePage', arguments: id);
  } else if (path.startsWith("/payment/confirm")) {
    Navigator.pushNamed(NavigationKey.currentState.currentContext, '/PaymentConfirmation');
  }
}